import { useState, useEffect, useCallback, useRef } from "react";
import {
  AreaChart, Area, LineChart, Line, BarChart, Bar,
  RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
  ScatterChart, Scatter, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from "recharts";

/* ═══════════════════════════════════════════════════════════════
   CONFIG — change API_BASE if backend runs on different port
═══════════════════════════════════════════════════════════════ */
const API_BASE = "http://localhost:5000";

/* ═══════════════════════════════════════════════════════════════
   REAL HOURLY DATA from your CSV (pre-computed)
   These are the actual averages from your dataset
═══════════════════════════════════════════════════════════════ */
const REAL_HOURLY = [
  {h:"0:00",total:43,cars:14,trucks:26,bikes:2,buses:1},
  {h:"1:00",total:42,cars:14,trucks:25,bikes:2,buses:1},
  {h:"2:00",total:43,cars:14,trucks:27,bikes:1,buses:1},
  {h:"3:00",total:45,cars:15,trucks:27,bikes:2,buses:1},
  {h:"4:00",total:98,cars:67,trucks:18,bikes:8,buses:5},
  {h:"5:00",total:114,cars:82,trucks:15,bikes:10,buses:7},
  {h:"6:00",total:167,cars:113,trucks:7,bikes:28,buses:19},
  {h:"7:00",total:166,cars:112,trucks:7,bikes:27,buses:20},
  {h:"8:00",total:168,cars:113,trucks:7,bikes:27,buses:21},
  {h:"9:00",total:126,cars:75,trucks:13,bikes:20,buses:18},
  {h:"10:00",total:117,cars:65,trucks:16,bikes:18,buses:18},
  {h:"11:00",total:103,cars:58,trucks:24,bikes:12,buses:9},
  {h:"12:00",total:104,cars:59,trucks:24,bikes:12,buses:9},
  {h:"13:00",total:122,cars:69,trucks:16,bikes:18,buses:19},
  {h:"14:00",total:125,cars:70,trucks:13,bikes:21,buses:21},
  {h:"15:00",total:120,cars:70,trucks:13,bikes:18,buses:19},
  {h:"16:00",total:178,cars:119,trucks:9,bikes:28,buses:22},
  {h:"17:00",total:178,cars:118,trucks:10,bikes:28,buses:22},
  {h:"18:00",total:162,cars:105,trucks:13,bikes:24,buses:20},
  {h:"19:00",total:121,cars:75,trucks:20,bikes:15,buses:11},
  {h:"20:00",total:118,cars:74,trucks:20,bikes:13,buses:11},
  {h:"21:00",total:115,cars:70,trucks:21,bikes:13,buses:11},
  {h:"22:00",total:43,cars:13,trucks:27,bikes:2,buses:1},
  {h:"23:00",total:42,cars:13,trucks:26,bikes:2,buses:1},
];

const REAL_WEEKLY = [
  {day:"Monday",   avg:110, peak:279},
  {day:"Tuesday",  avg:111, peak:279},
  {day:"Wednesday",avg:112, peak:279},
  {day:"Thursday", avg:111, peak:279},
  {day:"Friday",   avg:107, peak:279},
  {day:"Saturday", avg:112, peak:279},
  {day:"Sunday",   avg:111, peak:279},
];

const REAL_SITUATION = [
  {name:"Normal", value:5279, color:"#eab308"},
  {name:"Heavy",  value:1819, color:"#f97316"},
  {name:"Low",    value:1138, color:"#22c55e"},
  {name:"High",   value:692,  color:"#ef4444"},
];

const REAL_FEAT_IMP = [
  {f:"Total Vehicles", imp:32.4},
  {f:"Car Count",      imp:18.4},
  {f:"Truck Count",    imp:14.3},
  {f:"Bus Count",      imp:13.8},
  {f:"Car Ratio",      imp:5.0},
  {f:"Truck+Bus Ratio",imp:8.2},
  {f:"Hour of Day",    imp:2.1},
  {f:"Bike Count",     imp:3.8},
].sort((a,b)=>b.imp-a.imp);

/* ═══════════════════════════════════════════════════════════════
   ROAD NETWORK (Hyderabad zones mapped to your data)
═══════════════════════════════════════════════════════════════ */
const NODES = {
  HTC:{id:"HTC",name:"HITEC City",       x:18,y:18},
  GCB:{id:"GCB",name:"Gachibowli",       x:10,y:35},
  MDP:{id:"MDP",name:"Mehdipatnam",      x:22,y:55},
  JUB:{id:"JUB",name:"Jubilee Hills",    x:38,y:36},
  BAN:{id:"BAN",name:"Banjara Hills",    x:48,y:50},
  KPL:{id:"KPL",name:"Kukatpally",       x:28,y:10},
  SEC:{id:"SEC",name:"Secunderabad",     x:68,y:22},
  CHK:{id:"CHK",name:"Chikkadpally",     x:62,y:42},
  LBN:{id:"LBN",name:"LB Nagar",         x:72,y:72},
  UPL:{id:"UPL",name:"Uppal",            x:82,y:50},
  NAM:{id:"NAM",name:"Nampally",         x:52,y:62},
  OLD:{id:"OLD",name:"Old City",         x:55,y:78},
};
const EDGES = [
  {from:"HTC",to:"GCB",dist:8},{from:"HTC",to:"KPL",dist:6},{from:"HTC",to:"JUB",dist:10},
  {from:"GCB",to:"MDP",dist:9},{from:"GCB",to:"JUB",dist:11},{from:"KPL",to:"SEC",dist:14},
  {from:"JUB",to:"BAN",dist:6},{from:"JUB",to:"SEC",dist:18},{from:"MDP",to:"BAN",dist:7},
  {from:"MDP",to:"NAM",dist:8},{from:"BAN",to:"CHK",dist:9},{from:"BAN",to:"NAM",dist:7},
  {from:"SEC",to:"CHK",dist:8},{from:"SEC",to:"UPL",dist:16},{from:"CHK",to:"NAM",dist:6},
  {from:"CHK",to:"LBN",dist:14},{from:"CHK",to:"UPL",dist:12},{from:"NAM",to:"OLD",dist:5},
  {from:"OLD",to:"LBN",dist:10},{from:"UPL",to:"LBN",dist:11},
];

/* ═══════════════════════════════════════════════════════════════
   HELPERS
═══════════════════════════════════════════════════════════════ */
const SIT_COLOR = {low:"#22c55e",normal:"#eab308",heavy:"#f97316",high:"#ef4444"};
const SIT_SCORE = {low:20,normal:45,heavy:70,high:90};

function scoreToColor(s){ return s<30?"#22c55e":s<55?"#eab308":s<75?"#f97316":"#ef4444"; }

// Dijkstra
function dijkstra(liveEdges, start, end){
  const graph={};
  liveEdges.forEach(e=>{
    [e.from,e.to].forEach(n=>{ if(!graph[n]) graph[n]=[]; });
    const tt = e.dist / Math.max(5, 65-e.score*0.55) * 60;
    graph[e.from].push({node:e.to,  cost:tt, score:e.score, color:e.color});
    graph[e.to].push(  {node:e.from,cost:tt, score:e.score, color:e.color});
  });
  const dist={},prev={},vis=new Set();
  Object.keys(NODES).forEach(n=>dist[n]=Infinity);
  dist[start]=0;
  const pq=[[0,start]];
  while(pq.length){
    pq.sort((a,b)=>a[0]-b[0]);
    const [d,u]=pq.shift();
    if(vis.has(u)) continue; vis.add(u);
    if(u===end) break;
    (graph[u]||[]).forEach(({node,cost,score,color})=>{
      const nd=d+cost;
      if(nd<dist[node]){ dist[node]=nd; prev[node]={from:u,score,color}; pq.push([nd,node]); }
    });
  }
  const path=[]; let cur=end;
  while(cur){ path.unshift(cur); cur=prev[cur]?.from; }
  const segs=path.slice(1).map((n,i)=>({from:path[i],to:n,...prev[n]}));
  return {path,segs,totalTime:Math.round(dist[end])};
}

/* ═══════════════════════════════════════════════════════════════
   COMPONENTS
═══════════════════════════════════════════════════════════════ */
const C={bg:"#030712",surface:"#0b1120",border:"#1a2744",text:"#e2e8f0",muted:"#5a7098",accent:"#3b82f6"};

function Card({children,style={}}){
  return <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:12,padding:18,...style}}>{children}</div>;
}
function STitle({children,right}){
  return(
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <div style={{color:C.muted,fontSize:10,letterSpacing:2,textTransform:"uppercase"}}>{children}</div>
      {right&&<div>{right}</div>}
    </div>
  );
}
function Chip({label,color}){
  return <span style={{background:color+"22",color,border:`1px solid ${color}44`,borderRadius:99,padding:"2px 10px",fontSize:10,fontWeight:700,letterSpacing:.8}}>{label}</span>;
}
function StatCard({icon,label,value,sub,accent}){
  return(
    <div style={{background:C.surface,border:`1px solid ${accent}22`,borderLeft:`3px solid ${accent}`,borderRadius:10,padding:"12px 14px"}}>
      <div style={{fontSize:18}}>{icon}</div>
      <div style={{color:C.muted,fontSize:9,letterSpacing:1,textTransform:"uppercase",margin:"4px 0 2px"}}>{label}</div>
      <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:20,fontWeight:700,color:"#f1f5f9"}}>{value}</div>
      <div style={{fontSize:9,color:accent}}>{sub}</div>
    </div>
  );
}

/* SVG Map */
function TrafficMap({liveEdges,route,origin,dest,onNodeClick,selNode}){
  const W=700,H=440;
  const px=x=>x/100*W, py=y=>y/100*H;
  const isRouteEdge=(f,t)=>route?.segs?.find(s=>(s.from===f&&s.to===t)||(s.from===t&&s.to===f));
  return(
    <svg width="100%" viewBox={`0 0 ${W} ${H}`} style={{borderRadius:10,background:"#010a18",display:"block"}}>
      <defs>
        <filter id="glow"><feGaussianBlur stdDeviation="3" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
        <filter id="glow2"><feGaussianBlur stdDeviation="7" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
      </defs>
      {[15,30,45,60,75,90].map(v=>(
        <g key={v}>
          <line x1={0} y1={py(v)} x2={W} y2={py(v)} stroke="#ffffff04" strokeWidth={1}/>
          <line x1={px(v)} y1={0} x2={px(v)} y2={H} stroke="#ffffff04" strokeWidth={1}/>
        </g>
      ))}
      {liveEdges.map((e,i)=>{
        const fn=NODES[e.from],tn=NODES[e.to]; if(!fn||!tn) return null;
        const ir=isRouteEdge(e.from,e.to);
        const col=ir?"#3b82f6":e.color;
        return(
          <g key={i}>
            <line x1={px(fn.x)} y1={py(fn.y)} x2={px(tn.x)} y2={py(tn.y)} stroke={col+"33"} strokeWidth={ir?8:5}/>
            <line x1={px(fn.x)} y1={py(fn.y)} x2={px(tn.x)} y2={py(tn.y)} stroke={col} strokeWidth={ir?4:2}
              strokeDasharray={ir?"14,5":"none"} filter={ir?"url(#glow)":"none"}>
              {ir&&<animate attributeName="stroke-dashoffset" from="0" to="-38" dur="1s" repeatCount="indefinite"/>}
            </line>
            <text x={(px(fn.x)+px(tn.x))/2} y={(py(fn.y)+py(tn.y))/2-5}
              textAnchor="middle" fontSize="9" fill={col} fontFamily="monospace" fontWeight="600">{e.score}%</text>
          </g>
        );
      })}
      {Object.values(NODES).map(n=>{
        const isO=n.id===origin,isD=n.id===dest,isR=route?.path?.includes(n.id),isSel=n.id===selNode;
        const r=isO||isD?13:isR?10:7;
        const col=isO?"#22c55e":isD?"#f97316":isR?"#3b82f6":"#2a3f5f";
        return(
          <g key={n.id} onClick={()=>onNodeClick(n.id)} style={{cursor:"pointer"}}>
            <circle cx={px(n.x)} cy={py(n.y)} r={r+10} fill={col} opacity=".08"/>
            <circle cx={px(n.x)} cy={py(n.y)} r={r} fill={col+"44"} stroke={col} strokeWidth={isSel?3:1.5}
              filter={isO||isD?"url(#glow2)":isR?"url(#glow)":"none"}/>
            <text x={px(n.x)} y={py(n.y)+4} textAnchor="middle" fontSize="8" fill="#fff" fontWeight="bold" fontFamily="monospace">{n.id}</text>
            <text x={px(n.x)} y={py(n.y)+r+13} textAnchor="middle" fontSize="7.5" fill="#64748b" fontFamily="sans-serif">{n.name}</text>
          </g>
        );
      })}
      <g>
        {[["#22c55e","Low"],["#eab308","Normal"],["#f97316","Heavy"],["#ef4444","High"],["#3b82f6","Route"]].map(([c,l],i)=>(
          <g key={l} transform={`translate(${10+i*78},${H-16})`}>
            <rect width={8} height={8} rx={2} fill={c} y={-6}/><text x={12} fontSize="9" fill="#5a7098" fontFamily="sans-serif">{l}</text>
          </g>
        ))}
      </g>
    </svg>
  );
}

/* ═══════════════════════════════════════════════════════════════
   MAIN APP
═══════════════════════════════════════════════════════════════ */
export default function App(){
  const [tab,      setTab]      = useState("map");
  const [liveTime, setLiveTime] = useState(new Date());
  const [backendOk,setBackendOk]= useState(null); // null=checking, true/false
  const [liveEdges,setLiveEdges]= useState([]);
  const [route,    setRoute]    = useState(null);
  const [altRoute, setAltRoute] = useState(null);
  const [origin,   setOrigin]   = useState("HTC");
  const [dest,     setDest]     = useState("LBN");
  const [selNode,  setSelNode]  = useState(null);
  const [sensorFeed,setSensorFeed]=useState([]);

  // Predict tab state
  const [pHour,   setPHour]    = useState(new Date().getHours());
  const [pMinute, setPMinute]  = useState(0);
  const [pDow,    setPDow]     = useState(new Date().getDay()||1);
  const [pCars,   setPCars]    = useState(80);
  const [pBikes,  setPBikes]   = useState(10);
  const [pBuses,  setPBuses]   = useState(15);
  const [pTrucks, setPTrucks]  = useState(20);
  const [predResult,setPredResult]=useState(null);
  const [predLoading,setPredLoading]=useState(false);

  const now = new Date();
  const nowHour = now.getHours();

  // ── compute live edges from real hourly data ──────────────────
  const computeLiveEdges = useCallback((h)=>{
    const row = REAL_HOURLY[h] || REAL_HOURLY[8];
    const baseCong = Math.round((row.total / 180) * 85);
    return EDGES.map(e=>{
      const variation = Math.round((Math.random()-0.5)*18);
      const score = Math.max(5,Math.min(100, baseCong+variation));
      return {...e, score, color:scoreToColor(score)};
    });
  },[]);

  // ── check backend ─────────────────────────────────────────────
  useEffect(()=>{
    fetch(`${API_BASE}/health`)
      .then(r=>r.json())
      .then(()=>setBackendOk(true))
      .catch(()=>setBackendOk(false));
  },[]);

  // ── clock + live edge updates ─────────────────────────────────
  useEffect(()=>{
    const t=setInterval(()=>setLiveTime(new Date()),1000);
    return()=>clearInterval(t);
  },[]);

  useEffect(()=>{
    const update=()=>{
      const edges = computeLiveEdges(liveTime.getHours());
      setLiveEdges(edges);
      // update route
      if(origin!==dest){
        setRoute(dijkstra(edges,origin,dest));
        const alt=dijkstra(edges.map(e=>({...e,score:e.score*(1+(Math.random()-.3)*.4)})),origin,dest);
        setAltRoute(alt.path.join("")!==dijkstra(edges,origin,dest).path.join("")?alt:null);
      }
      // sensor feed
      const row=REAL_HOURLY[liveTime.getHours()]||REAL_HOURLY[8];
      const v=row.total+Math.round((Math.random()-.5)*20);
      setSensorFeed(p=>[...p.slice(-29),{
        t:liveTime.toLocaleTimeString("en",{hour:"2-digit",minute:"2-digit",second:"2-digit"}),
        total:v, cars:row.cars+Math.round((Math.random()-.5)*10),
        trucks:row.trucks+Math.round((Math.random()-.5)*5)
      }]);
    };
    update();
    const t=setInterval(update,3000);
    return()=>clearInterval(t);
  },[liveTime.getMinutes(),origin,dest]);

  // ── predict via backend ───────────────────────────────────────
  const runPredict = async()=>{
    setPredLoading(true);
    try{
      if(backendOk){
        const res = await fetch(`${API_BASE}/predict`,{
          method:"POST", headers:{"Content-Type":"application/json"},
          body:JSON.stringify({hour:pHour,minute:pMinute,dow:pDow,cars:pCars,bikes:pBikes,buses:pBuses,trucks:pTrucks})
        });
        setPredResult(await res.json());
      } else {
        // fallback simulation
        const total=pCars+pBikes+pBuses+pTrucks;
        const hourRow=REAL_HOURLY[pHour];
        const baseScore = Math.round((total/hourRow.total)*45 + (pHour>=7&&pHour<=9||pHour>=16&&pHour<=19?30:10));
        const score=Math.min(95,Math.max(5,baseScore));
        const sit=score<30?"low":score<55?"normal":score<75?"heavy":"high";
        setPredResult({situation:sit,score,color:SIT_COLOR[sit],speed:Math.round(Math.max(8,65-score*.58)),delay:Math.round(score/3.5),confidence:87.3,total_vehicles:total,probabilities:{low:sit==="low"?87:5,normal:sit==="normal"?87:8,heavy:sit==="heavy"?87:5,high:sit==="high"?87:2}});
      }
    } catch(err){ console.error(err); }
    setPredLoading(false);
  };

  const DAYS=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const NODE_IDS=Object.keys(NODES);
  const curRow=REAL_HOURLY[nowHour]||REAL_HOURLY[8];
  const curScore=Math.round((curRow.total/180)*80);
  const curColor=scoreToColor(curScore);
  const curSit=curScore<30?"Low":curScore<55?"Normal":curScore<75?"Heavy":"High";

  const TABS=[
    {id:"map",    label:"🗺️ Live Map"},
    {id:"predict",label:"🤖 Predict"},
    {id:"analyze",label:"📊 Analysis"},
    {id:"segment",label:"🛣️ Segments"},
    {id:"sensors",label:"📡 Sensors"},
    {id:"model",  label:"🧠 Model"},
  ];

  const ttStyle={background:"#0b1120",border:"1px solid #1a2744",borderRadius:8,fontSize:11,color:"#e2e8f0"};

  return(
    <div style={{minHeight:"100vh",background:C.bg,color:C.text,fontFamily:"'IBM Plex Sans','Segoe UI',sans-serif"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@300;400;600;700&family=JetBrains+Mono:wght@400;600&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:#030712}::-webkit-scrollbar-thumb{background:#1a2744;border-radius:3px}
        .tbtn:hover{background:rgba(59,130,246,.12)!important}
        input[type=range]{accent-color:#3b82f6;width:100%}
        select,input[type=number]{background:#0b1120;color:#e2e8f0;border:1px solid #1a2744;border-radius:6px;padding:7px 10px;font-size:12px;outline:none;width:100%}
        .fade{animation:fi .3s ease}
        @keyframes fi{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        .pulse{animation:pu 2s infinite}@keyframes pu{0%,100%{opacity:1}50%{opacity:.25}}
        .blink{animation:bl 1s step-end infinite}@keyframes bl{0%,100%{opacity:1}50%{opacity:0}}
        .rbtn:hover{filter:brightness(1.15);transform:translateY(-1px)}
