                  ["🚛","Trucks",`${curRow.trucks}/hr`,"Heavy vehicles","#f97316"],
                  ["⚡","Est. Speed",`${Math.round(Math.max(8,65-curScore*.55))} km/h`,"Current estimate","#a78bfa"],
