                            <span style={{background:i===0?"#22c55e22":i===r.path.length-1?"#f9731622":"#1a2744",color:i===0?"#22c55e":i===r.path.length-1?"#f97316":"#94a3b8",border:`1px solid ${i===0?"#22c55e44":i===r.path.length-1?"#f9731644":"#243050"}`,borderRadius:6,padding:"3px 8px",fontSize:11,fontFamily:"'JetBrains Mono',monospace",fontWeight:600}}>{n}</span>
                            {i<r.path.length-1&&<span style={{color:"#243050",fontSize:12}}>→</span>}
