              </Card>

              {selNode&&NODES[selNode]&&(
                <Card style={{border:`1px solid #3b82f644`}}>
                  <STitle>NODE · {selNode}</STitle>
                  <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>{NODES[selNode].name}</div>
                  {(()=>{
                    const ne=liveEdges.filter(e=>e.from===selNode||e.to===selNode);
                    const ac=Math.round(ne.reduce((a,e)=>a+e.score,0)/(ne.length||1));
                    return(<>
                      <Chip label={ac<30?"Low":ac<55?"Normal":ac<75?"Heavy":"High"} color={scoreToColor(ac)}/>
                      <div style={{marginTop:12,display:"flex",flexDirection:"column",gap:7}}>
