                    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginTop:20}}>
                      {[["⚡","Speed",predResult.speed+" km/h"],["🕐","Delay",predResult.delay+" min"],["🚗","Vehicles",predResult.total_vehicles]].map(([ic,lb,vl])=>(
