                    <Legend wrapperStyle={{fontSize:10,color:C.muted}}/>
                    <Line type="monotone" dataKey="cars"   stroke="#3b82f6" dot={false} strokeWidth={2} name="Cars"/>
                    <Line type="monotone" dataKey="trucks" stroke="#ef4444" dot={false} strokeWidth={2} name="Trucks"/>
                    <Line type="monotone" dataKey="buses"  stroke="#f97316" dot={false} strokeWidth={1.5} name="Buses"/>
                    <Line type="monotone" dataKey="bikes"  stroke="#22c55e" dot={false} strokeWidth={1.5} name="Bikes"/>
                  </LineChart>
                </ResponsiveContainer>
              </Card>
            </div>
          </div>
        )}

        {/* ══════════ SEGMENTS ══════════ */}
        {tab==="segment"&&(
          <div style={{display:"flex",flexDirection:"column",gap:18}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
              {[
                ["Total Segments",EDGES.length,"#3b82f6"],
                ["Critical >75%",liveEdges.filter(e=>e.score>75).length,"#ef4444"],
                ["Heavy 50-75%",liveEdges.filter(e=>e.score>50&&e.score<=75).length,"#f97316"],
                ["Clear <30%",liveEdges.filter(e=>e.score<30).length,"#22c55e"],
              ].map(([l,v,c])=>(
                <Card key={l} style={{border:`1px solid ${c}22`,borderLeft:`3px solid ${c}`,textAlign:"center"}}>
                  <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:30,fontWeight:700,color:c}}>{v}</div>
                  <div style={{fontSize:10,color:C.muted,marginTop:4,letterSpacing:1}}>{l.toUpperCase()}</div>
                </Card>
              ))}
            </div>
            <Card>
              <STitle>ALL SEGMENTS — LIVE RF SCORES</STitle>
              <div style={{overflowX:"auto"}}>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                  <thead>
                    <tr style={{borderBottom:`1px solid ${C.border}`}}>
                      {["Segment","From","To","Score","Speed","Delay","Status","Bar"].map(h=>(
                        <th key={h} style={{padding:"8px 12px",textAlign:"left",color:C.muted,fontSize:9,letterSpacing:1,fontWeight:600}}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {[...liveEdges].sort((a,b)=>b.score-a.score).map((e,i)=>{
                      const spd=Math.round(Math.max(8,65-e.score*.55));
                      const dly=Math.round(e.score/3.5);
                      const sit=e.score<30?"LOW":e.score<55?"NORMAL":e.score<75?"HEAVY":"HIGH";
                      return(
                        <tr key={i} className="nrow" style={{borderBottom:"1px solid #060e1e",background:i%2===0?"transparent":"rgba(26,39,68,.2)"}}>
                          <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",fontSize:11,color:"#94a3b8"}}>{e.from}→{e.to}</td>
                          <td style={{padding:"9px 12px",color:C.text,fontSize:11}}>{NODES[e.from]?.name}</td>
                          <td style={{padding:"9px 12px",color:C.text,fontSize:11}}>{NODES[e.to]?.name}</td>
                          <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",color:e.color,fontWeight:700}}>{e.score}%</td>
                          <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",color:"#22c55e"}}>{spd} km/h</td>
                          <td style={{padding:"9px 12px",fontFamily:"'JetBrains Mono',monospace",color:"#f97316"}}>{dly} min</td>
                          <td style={{padding:"9px 12px"}}><Chip label={sit} color={e.color}/></td>
                          <td style={{padding:"9px 12px",width:80}}>
                            <div style={{background:"#1a2744",borderRadius:3,height:5,overflow:"hidden"}}>
                              <div style={{height:"100%",width:`${e.score}%`,background:e.color,borderRadius:3,transition:"width .5s"}}/>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </Card>
          </div>
        )}

        {/* ══════════ SENSORS ══════════ */}
        {tab==="sensors"&&(
          <div style={{display:"flex",flexDirection:"column",gap:18}}>
            <Card>
              <STitle right={<div style={{display:"flex",alignItems:"center",gap:6}}><div className="blink" style={{width:7,height:7,borderRadius:"50%",background:"#22c55e"}}/><span style={{fontSize:9,color:"#22c55e"}}>LIVE STREAM</span></div>}>REAL-TIME VEHICLE FEED — BASED ON YOUR CSV AVERAGES</STitle>
              <ResponsiveContainer width="100%" height={240}>
                <LineChart data={sensorFeed}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#1a2744"/>
                  <XAxis dataKey="t" tick={{fill:"#475569",fontSize:8}} interval="preserveStartEnd"/>
                  <YAxis tick={{fill:"#475569",fontSize:9}}/>
                  <Tooltip contentStyle={ttStyle}/>
                  <Legend wrapperStyle={{fontSize:10,color:C.muted}}/>
                  <Line type="monotone" dataKey="total"  stroke="#3b82f6" dot={false} strokeWidth={2.5} name="Total Vehicles" isAnimationActive={false}/>
                  <Line type="monotone" dataKey="cars"   stroke="#22c55e" dot={false} strokeWidth={2} name="Cars" isAnimationActive={false}/>
                  <Line type="monotone" dataKey="trucks" stroke="#ef4444" dot={false} strokeWidth={1.5} name="Trucks" isAnimationActive={false}/>
                </LineChart>
              </ResponsiveContainer>
            </Card>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14}}>
              {[
                ["Loop Detectors","Count axles at road surface","24","#3b82f6",true],
                ["CCTV / CV","Vehicle detection via camera","18","#a78bfa",true],
                ["GPS Probes","Floating car data","12","#22c55e",true],
                ["Bluetooth","MAC address scanning","30","#eab308",true],
                ["RFID / FASTag","Toll point readers","8","#f97316",false],
                ["Weather Nodes","Env. sensors","6","#64748b",true],
              ].map(([nm,desc,cnt,col,online])=>(
                <Card key={nm} style={{border:`1px solid ${col}22`}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
                    <div style={{fontWeight:600,fontSize:13}}>{nm}</div>
                    <Chip label={online?"ONLINE":"OFFLINE"} color={online?"#22c55e":"#ef4444"}/>
                  </div>
                  <div style={{fontSize:10,color:C.muted,marginBottom:10}}>{desc}</div>
                  <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:28,fontWeight:700,color:col}}>{cnt}</div>
                  <div style={{background:"#030712",borderRadius:4,height:4,overflow:"hidden",marginTop:8}}>
                    <div style={{height:"100%",width:online?"100%":"30%",background:col,borderRadius:4}}/>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        )}

        {/* ══════════ MODEL ══════════ */}
        {tab==="model"&&(
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:18}}>
            <div style={{display:"flex",flexDirection:"column",gap:14}}>
              <Card>
                <STitle>MODEL PERFORMANCE</STitle>
                {[["Algorithm","Random Forest","#22c55e"],["Estimators","200 trees","#3b82f6"],["Max Depth","15","#3b82f6"],["Features","12","#3b82f6"],["Training Records","7,143 (80%)","#3b82f6"],["Test Records","1,785 (20%)","#3b82f6"],["Accuracy","92.89%","#22c55e"],["Macro F1","0.90","#22c55e"],["Classes","low, normal, heavy, high","#eab308"]].map(([k,v,c])=>(
                  <div key={k} style={{display:"flex",justifyContent:"space-between",borderBottom:"1px solid #060e1e",padding:"8px 0"}}>
                    <span style={{fontSize:11,color:C.muted}}>{k}</span>
                    <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:11,color:c}}>{v}</span>
                  </div>
                ))}
              </Card>
              <Card>
                <STitle>CLASS DISTRIBUTION — YOUR DATA</STitle>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={REAL_SITUATION}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1a2744"/>
                    <XAxis dataKey="name" tick={{fill:"#475569",fontSize:10}}/>
                    <YAxis tick={{fill:"#475569",fontSize:9}}/>
                    <Tooltip contentStyle={ttStyle}/>
                    <Bar dataKey="value" name="Records" radius={[4,4,0,0]}>
                      {REAL_SITUATION.map((s,i)=><Cell key={i} fill={s.color}/>)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </Card>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:14}}>
              <Card>
                <STitle>FEATURE IMPORTANCE — WHAT DRIVES PREDICTIONS</STitle>
                <ResponsiveContainer width="100%" height={260}>
                  <BarChart layout="vertical" data={REAL_FEAT_IMP}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1a2744"/>
                    <XAxis type="number" tick={{fill:"#475569",fontSize:9}}/>
                    <YAxis dataKey="f" type="category" tick={{fill:"#94a3b8",fontSize:10}} width={120}/>
                    <Tooltip contentStyle={ttStyle}/>
                    <Bar dataKey="imp" name="Importance %" fill="#3b82f6" radius={[0,4,4,0]}/>
                  </BarChart>
                </ResponsiveContainer>
              </Card>
              <Card>
                <STitle>CONFUSION MATRIX (SIMULATED)</STitle>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:4,textAlign:"center"}}>
                  {["","Low","Normal","Heavy","High"].map((h,i)=>(
                    <div key={i} style={{padding:"6px 4px",fontSize:10,color:C.muted,fontWeight:i===0?"":"600"}}>{h}</div>
                  ))}
                  {[["Low","182","11","0","0"],["Normal","14","996","22","3"],["Heavy","0","1","348","3"],["High","0","7","18","123"]].map(([row,...vals])=>(
                    <>
                      <div key={row} style={{padding:"6px 4px",fontSize:10,color:C.muted,fontWeight:600}}>{row}</div>
                      {vals.map((v,i)=>(
                        <div key={i} style={{padding:"8px 4px",borderRadius:6,background:vals.indexOf(v)===i&&parseInt(v)>50?"#3b82f622":"#1a2744",color:vals.indexOf(v)===i&&parseInt(v)>50?"#3b82f6":C.muted,fontFamily:"'JetBrains Mono',monospace",fontSize:12}}>{v}</div>
                      ))}
                    </>
                  ))}
                </div>
              </Card>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
